INSERT INTO `system_settings` (`category`, `setting_key`, `setting_value`, `description`, `updated_at`) VALUES
INSERT IGNORE INTO `cms_pages` VALUES (1,'about-us','fr_FR','À propos de nous','<h2>Bienvenue sur Pinakes</h2>\n<p>Pinakes est un système de gestion de bibliothèque moderne, intuitif et entièrement gratuit. Il a été conçu pour simplifier la catalogisation des livres, la gestion des emprunts et l''administration de toute bibliothèque, quelle que soit sa taille.</p>\n\n<h3>🎯 Notre mission</h3>\n<p>Rendre la gestion de bibliothèque accessible à tous, sans frais de licence ni restrictions. Pinakes est 100 % Open Source, libre et gratuit pour tous.</p>\n\n<h3>✨ Fonctionnalités principales</h3>\n<ul>\n    <li><strong>Catalogisation intelligente :</strong> Import automatique des données via ISBN, organisation par catégories, auteurs et classifications personnalisées</li>\n    <li><strong>Gestion des emprunts :</strong> Système complet de gestion des prêts, délais, renouvellements et retours</li>\n    <li><strong>Notifications automatiques :</strong> Rappels par e-mail pour les échéances et la communication avec les utilisateurs</li>\n    <li><strong>Interface moderne :</strong> Design responsive, optimisé pour bureau, tablette et smartphone</li>\n    <li><strong>100 % Open Source :</strong> Code libre, personnalisable et sans coûts cachés</li>\n</ul>\n\n<h3>🚀 Pourquoi choisir Pinakes ?</h3>\n<p>Pinakes est né du besoin d''un outil professionnel, fiable et gratuit pour gérer les bibliothèques scolaires, associatives et les collections privées. Pas besoin d''être expert en informatique : l''interface intuitive permet à chacun de démarrer immédiatement.</p>\n\n<h3>📖 Commencer maintenant</h3>\n<p>Personnalisez cette page avec des informations sur votre bibliothèque, votre équipe et vos services. Accédez au panneau d''administration (CMS &gt; Pages) pour modifier ce contenu et le rendre unique.</p>\n\n<p><em>Il s''agit d''un contenu d''exemple. Personnalisez-le pour raconter l''histoire de votre bibliothèque !</em></p>',NULL,NULL,1,'2025-10-01 10:35:27','2025-10-01 10:35:27');
INSERT IGNORE INTO `cms_pages` VALUES (2,'privacy-policy','fr_FR','Politique de confidentialité','<h2>Politique de confidentialité</h2>\n<p>Il s''agit d''une page d''espace réservé pour la politique de confidentialité. Adaptez ce contenu conformément à la réglementation en vigueur (RGPD) et aux exigences spécifiques de votre bibliothèque.</p>\n\n<h3>1. Responsable du traitement</h3>\n<p>[Indiquez ici les coordonnées du responsable du traitement : nom, adresse, e-mail, téléphone]</p>\n\n<h3>2. Données collectées</h3>\n<p>Les données personnelles collectées via ce système comprennent :</p>\n<ul>\n    <li>Données personnelles (nom, prénom, date de naissance)</li>\n    <li>Coordonnées (e-mail, téléphone, adresse)</li>\n    <li>Données relatives aux emprunts effectués</li>\n</ul>\n\n<h3>3. Finalité du traitement</h3>\n<p>Les données sont traitées exclusivement pour :</p>\n<ul>\n    <li>Gestion de l''inscription des utilisateurs</li>\n    <li>Gestion des emprunts de la bibliothèque</li>\n    <li>Envoi de communications relatives aux emprunts (échéances, renouvellements)</li>\n</ul>\n\n<h3>4. Droits des personnes concernées</h3>\n<p>Les personnes concernées ont le droit d''accès, de rectification, d''effacement ou de limitation du traitement de leurs données, tel que prévu par le règlement (UE) 2016/679 (RGPD).</p>\n\n<p><strong>IMPORTANT :</strong> Il s''agit d''un modèle. Consultez un expert juridique pour créer une politique de confidentialité conforme à la réglementation en vigueur.</p>\n\n<p><em>Accédez au panneau d''administration (CMS &gt; Pages) pour personnaliser cette page.</em></p>',NULL,NULL,1,'2025-10-01 10:35:27','2025-10-01 10:35:27');
INSERT IGNORE INTO `email_templates` VALUES (1,'admin_new_registration','fr_FR','👤 Nouvelle demande d''inscription','<h2>Nouvelle demande d''inscription</h2>\n<p>Un nouvel utilisateur a demandé l''accès au système de bibliothèque :</p>\n<p><strong>Données de l''utilisateur :</strong></p>\n<ul>\n    <li>Nom : {{first_name}} {{last_name}}</li>\n    <li>E-mail : {{email}}</li>\n    <li>Numéro de carte : {{card_code}}</li>\n    <li>Date d''inscription : {{registration_date}}</li>\n</ul>\n<p><a href=\"{{admin_users_url}}\" style=\"background-color: #3b82f6; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px;\">Gérer les utilisateurs</a></p>','E-mail envoyé aux administrateurs lors d''une nouvelle inscription d''utilisateur.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (2,'admin_new_review','fr_FR','⭐ Nouvel avis à approuver','<h2>Nouvel avis à approuver</h2>\n<p>Un nouvel avis a été soumis pour le livre suivant :</p>\n<p><strong>Livre :</strong> {{book_title}}</p>\n<div style=\"background-color: #fff7ed; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #f59e0b;\">\n    <p><strong>Note :</strong> {{stars}} étoiles ⭐</p>\n    <p><strong>Utilisateur :</strong> {{user_name}} ({{user_email}})</p>\n    <p><strong>Date de l''avis :</strong> {{review_date}}</p>\n    <p><strong>Titre :</strong> {{review_title}}</p>\n    <p><strong>Description :</strong></p>\n    <p style=\"white-space: pre-line;\">{{review_description}}</p>\n</div>\n<p style=\"text-align: center;\">\n    <a href=\"{{approval_link}}\" style=\"background-color: #10b981; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; display: inline-block; margin: 10px;\">Gérer l''avis</a>\n</p>\n<p><em>Pour approuver ou refuser cet avis, accédez au panneau d''administration.</em></p>','Envoyé aux administrateurs lorsqu''un nouvel avis est soumis pour approbation.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (3,'loan_approved','fr_FR','✅ Votre demande d''emprunt a été approuvée !','<h2>Votre demande d''emprunt a été approuvée !</h2>\n<p>Bonjour {{user_name}},</p>\n<p>Nous avons le plaisir de vous informer que votre demande d''emprunt a été <strong>approuvée</strong> !</p>\n<p><strong>Détails de l''emprunt :</strong></p>\n<ul>\n    <li>Livre : {{book_title}}</li>\n    <li>Date de début : {{start_date}}</li>\n    <li>Date de retour : {{end_date}}</li>\n    <li>Durée : {{loan_days}} jours</li>\n</ul>\n<div style=\"background-color: #ecfdf5; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #10b981;\">\n    <p><strong>📦 Retrait du livre</strong></p>\n    <p>{{pickup_instructions}}</p>\n</div>\n<p><strong>Important :</strong> Veuillez retourner le livre avant la date d''échéance. Vous recevrez un rappel quelques jours avant l''expiration.</p>\n<p>Bonne lecture !</p>','Envoyé à l''utilisateur lorsqu''un administrateur approuve une demande d''emprunt.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (4,'loan_rejected','fr_FR','❌ Votre demande d''emprunt n''a pas été approuvée','<h2>Votre demande d''emprunt n''a pas été approuvée</h2>\n<p>Bonjour {{user_name}},</p>\n<p>Nous avons le regret de vous informer que votre demande d''emprunt pour le livre <strong>\"{{book_title}}\"</strong> n''a pas été approuvée.</p>\n<div style=\"background-color: #fef2f2; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #ef4444;\">\n    <p><strong>Motif :</strong></p>\n    <p>{{rejection_reason}}</p>\n</div>\n<p>Si vous avez des questions ou avez besoin d''informations complémentaires, n''hésitez pas à nous contacter.</p>\n<p>Cordialement,<br>L''équipe de la bibliothèque</p>','Envoyé à l''utilisateur lorsqu''un administrateur refuse une demande d''emprunt.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (5,'loan_expiring_warning','fr_FR','⚠️ Votre emprunt expire bientôt','<h2>Rappel d''échéance d''emprunt</h2>\n<p>Bonjour {{user_name}},</p>\n<p>Nous vous rappelons que votre emprunt expire bientôt :</p>\n<p><strong>Détails de l''emprunt :</strong></p>\n<ul>\n    <li>Livre : {{book_title}}</li>\n    <li>Date d''échéance : {{due_date}}</li>\n    <li>Jours restants : {{days_remaining}}</li>\n</ul>\n<div style=\"background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0;\">\n    <p><strong>⏰ Action requise</strong></p>\n    <p>Pour éviter des pénalités, veuillez retourner le livre avant la date d''échéance ou contacter la bibliothèque pour un éventuel renouvellement.</p>\n</div>\n<p>Merci pour votre coopération !</p>','E-mail envoyé à l''utilisateur 3 jours avant l''expiration de l''emprunt.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (6,'loan_overdue_admin','fr_FR','Emprunt #{{loan_id}} en retard','<h2>Emprunt en retard</h2>\n<p>L''emprunt <strong>#{{loan_id}}</strong> a atteint le statut <strong>en retard</strong>.</p>\n<ul>\n  <li><strong>Livre :</strong> {{book_title}}</li>\n  <li><strong>Utilisateur :</strong> {{user_name}} ({{user_email}})</li>\n  <li><strong>Date d''emprunt :</strong> {{loan_date}}</li>\n  <li><strong>Date de retour :</strong> {{due_date}}</li>\n</ul>\n<p>Veuillez contacter l''utilisateur pour demander le retour du livre.</p>','Notifie les administrateurs lorsqu''un emprunt est en retard.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (7,'loan_overdue_notification','fr_FR','🚨 Emprunt en retard - Action requise','<h2>Emprunt en retard</h2>\n<p>Bonjour {{user_name}},</p>\n<p>Votre emprunt est en retard et doit être retourné immédiatement :</p>\n<p><strong>Détails de l''emprunt :</strong></p>\n<ul>\n    <li>Livre : {{book_title}}</li>\n    <li>Date de retour : {{due_date}}</li>\n    <li>En retard depuis : {{days_overdue}} jours</li>\n</ul>\n<div style=\"background-color: #fef2f2; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #ef4444;\">\n    <p><strong>🚨 Action urgente requise</strong></p>\n    <p>Le livre doit être retourné immédiatement. Les retards peuvent entraîner des pénalités et une suspension du service.</p>\n</div>\n<p>Veuillez contacter la bibliothèque dès que possible pour résoudre cette situation.</p>','E-mail envoyé à l''utilisateur lorsque l''emprunt est en retard.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (8,'loan_request_notification','fr_FR','📚 Nouvelle demande d''emprunt','<h2>Nouvelle demande d''emprunt</h2>\n<p>Une nouvelle demande d''emprunt a été soumise :</p>\n<p><strong>Détails :</strong></p>\n<ul>\n    <li>Livre : {{book_title}}</li>\n    <li>Utilisateur : {{user_name}} ({{user_email}})</li>\n    <li>Date de début souhaitée : {{start_date}}</li>\n    <li>Date de fin souhaitée : {{end_date}}</li>\n    <li>Date de la demande : {{request_date}}</li>\n</ul>\n<p><a href=\"{{approve_url}}\" style=\"background-color: #10b981; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px;\">Gérer la demande</a></p>','E-mail envoyé aux administrateurs lorsqu''un utilisateur demande un emprunt.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (9,'user_account_approved','fr_FR','Compte approuvé - Bienvenue dans la bibliothèque !','<h2>Votre compte a été approuvé !</h2>\n<p>Bonjour {{first_name}} {{last_name}},</p>\n<p>Nous avons le plaisir de vous informer que votre compte a été approuvé par un administrateur.</p>\n<p>Vous pouvez maintenant vous connecter et réserver des livres !</p>\n<p><strong>Vos informations de compte :</strong></p>\n<ul>\n    <li>E-mail : {{email}}</li>\n    <li>Numéro de carte : {{card_code}}</li>\n</ul>\n<p><a href=\"{{login_url}}\" style=\"background-color: #3b82f6; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px;\">Se connecter maintenant</a></p>\n<p>Bienvenue dans notre bibliothèque numérique !</p>','E-mail envoyé lorsqu''un administrateur approuve le compte directement sans exiger la vérification par e-mail.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (10,'user_activation_with_verification','fr_FR','Activer votre compte - Confirmer votre e-mail','<h2>Votre compte a été approuvé !</h2>\n<p>Bonjour {{first_name}} {{last_name}},</p>\n<p>Nous avons le plaisir de vous informer que votre compte a été approuvé par un administrateur.</p>\n<p>📧 <strong>Confirmez votre adresse e-mail</strong></p>\n<p>Pour finaliser l''activation, cliquez sur le bouton ci-dessous pour confirmer votre adresse e-mail :</p>\n<p style=\"text-align: center; margin: 30px 0;\">\n    <a href=\"{{verification_url}}\" style=\"background-color: #10b981; color: white; padding: 12px 30px; text-decoration: none; border-radius: 8px; font-size: 16px; display: inline-block;\">✅ Confirmer l''e-mail</a>\n</p>\n<p><strong>Vos informations de compte :</strong></p>\n<ul>\n    <li>E-mail : {{email}}</li>\n    <li>Numéro de carte : {{card_code}}</li>\n</ul>\n<div style=\"background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0;\">\n    <p><strong>⏰ Important</strong></p>\n    <p>Le lien de confirmation est valide pendant 7 jours. Après confirmation, vous pourrez vous connecter et réserver des livres.</p>\n</div>\n<p>Si vous n''avez pas demandé cette inscription, vous pouvez ignorer cet e-mail.</p>','E-mail envoyé lorsqu''un administrateur approuve le compte et exige une vérification par e-mail.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (11,'user_registration_pending','fr_FR','Inscription reçue - Approbation en attente','<h2>Bienvenue {{first_name}} {{last_name}} !</h2>\n<p>Votre demande d''inscription a été reçue avec succès.</p>\n<p><strong>Informations du compte :</strong></p>\n<ul>\n    <li>E-mail : {{email}}</li>\n    <li>Numéro de carte : {{card_code}}</li>\n    <li>Date d''inscription : {{registration_date}}</li>\n</ul>\n{{verify_section}}\n<div style=\"background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0;\">\n    <p><strong>⏳ Compte en attente d''approbation</strong></p>\n    <p>Votre compte est en attente d''approbation par un administrateur. Vous recevrez un e-mail de confirmation dès que votre compte sera activé.</p>\n</div>\n<p>Merci d''avoir choisi notre système de bibliothèque !</p>','E-mail envoyé à l''utilisateur après l''inscription lorsque le compte est en attente d''approbation.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (12,'wishlist_book_available','fr_FR','📖 Livre de votre liste de souhaits maintenant disponible !','<h2>Bonne nouvelle !</h2>\n<p>Bonjour {{user_name}},</p>\n<p>Le livre que vous avez ajouté à votre liste de souhaits est maintenant disponible à l''emprunt :</p>\n<div style=\"background-color: #f0f9ff; padding: 20px; border-radius: 10px; border-left: 4px solid #3b82f6; margin: 20px 0;\">\n    <h3 style=\"color: #1e40af; margin: 0 0 10px 0;\">{{book_title}}</h3>\n    <p style=\"margin: 5px 0;\"><strong>Auteur :</strong> {{book_author}}</p>\n    <p style=\"margin: 5px 0;\"><strong>ISBN :</strong> {{book_isbn}}</p>\n    <p style=\"margin: 5px 0;\"><strong>Disponible à partir du :</strong> {{availability_date}}</p>\n</div>\n<div style=\"background-color: #ecfdf5; padding: 15px; border-radius: 5px; margin: 20px 0;\">\n    <p><strong>✨ Réservez maintenant !</strong></p>\n    <p>Le livre est maintenant disponible à la réservation. Dépêchez-vous avant que quelqu''un d''autre ne le réserve !</p>\n</div>\n<p style=\"text-align: center;\">\n    <a href=\"{{book_url}}\" style=\"background-color: #10b981; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; display: inline-block; margin: 10px;\">📚 Réserver maintenant</a>\n    <a href=\"{{wishlist_url}}\" style=\"background-color: #6b7280; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; display: inline-block; margin: 10px;\">❤️ Gérer ma liste de souhaits</a>\n</p>\n<p><em>Ce livre a été automatiquement retiré de votre liste de souhaits.</em></p>','E-mail envoyé lorsqu''un livre de la liste de souhaits devient disponible.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (13,'reservation_book_available','fr_FR','📚 Livre réservé prêt à être récupéré !','<h2>Votre livre est prêt à être récupéré !</h2>\n<p>Bonjour {{user_name}},</p>\n<p>Nous avons le plaisir de vous informer que le livre que vous avez réservé est maintenant disponible et prêt à être récupéré :</p>\n<div style=\"background-color: #f0f9ff; padding: 20px; border-radius: 10px; border-left: 4px solid #3b82f6; margin: 20px 0;\">\n    <h3 style=\"color: #1e40af; margin: 0 0 10px 0;\">{{book_title}}</h3>\n    <p style=\"margin: 5px 0;\"><strong>Auteur :</strong> {{book_author}}</p>\n    <p style=\"margin: 5px 0;\"><strong>ISBN :</strong> {{book_isbn}}</p>\n    <p style=\"margin: 5px 0;\"><strong>Période d''emprunt :</strong> {{start_date}} - {{end_date}}</p>\n</div>\n<div style=\"background-color: #ecfdf5; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #10b981;\">\n    <p><strong>📦 Prochaines étapes</strong></p>\n    <p>Rendez-vous à la bibliothèque pour récupérer le livre. Veuillez apporter une pièce d''identité.</p>\n</div>\n<p style=\"text-align: center;\">\n    <a href=\"{{book_url}}\" style=\"background-color: #3b82f6; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; display: inline-block; margin: 10px;\">📖 Voir le livre</a>\n    <a href=\"{{profile_url}}\" style=\"background-color: #6b7280; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; display: inline-block; margin: 10px;\">👤 Mes emprunts</a>\n</p>\n<p><em>Votre réservation a été convertie en emprunt en attente de confirmation de retrait.</em></p>','E-mail envoyé lorsqu''un livre réservé devient disponible et est converti en emprunt.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (14,'user_password_setup','fr_FR','🔐 Configurer votre mot de passe','<h2>Configurer votre mot de passe</h2>\n<p>Bonjour {{first_name}} {{last_name}},</p>\n<p>Votre compte sur <strong>{{app_name}}</strong> a été créé. Pour utiliser le système, vous devez configurer votre mot de passe.</p>\n<div style=\"background-color: #f0f9ff; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #3b82f6;\">\n    <p><strong>🔑 Configurer votre compte</strong></p>\n    <p>Cliquez sur le bouton ci-dessous pour définir votre mot de passe :</p>\n</div>\n<p style=\"text-align: center; margin: 30px 0;\">\n    <a href=\"{{reset_url}}\" style=\"background-color: #10b981; color: white; padding: 12px 30px; text-decoration: none; border-radius: 8px; font-size: 16px; display: inline-block;\">🔐 Définir mon mot de passe</a>\n</p>\n<div style=\"background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0;\">\n    <p><strong>⏰ Important</strong></p>\n    <p>Ce lien est valide pendant 24 heures. S''il expire, contactez un administrateur pour en obtenir un nouveau.</p>\n</div>\n<p>Si vous n''avez pas demandé cet e-mail, vous pouvez l''ignorer.</p>','E-mail envoyé aux nouveaux utilisateurs pour configurer leur mot de passe.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (15,'admin_invitation','fr_FR','🎉 Invitation d''administrateur','<h2>Bienvenue dans l''équipe !</h2>\n<p>Bonjour {{first_name}} {{last_name}},</p>\n<p>Vous avez été invité(e) en tant qu''administrateur sur <strong>{{app_name}}</strong>.</p>\n<div style=\"background-color: #f0f9ff; padding: 20px; border-radius: 10px; border-left: 4px solid #3b82f6; margin: 20px 0;\">\n    <h3 style=\"color: #1e40af; margin: 0 0 10px 0;\">Votre accès</h3>\n    <p>En tant qu''administrateur, vous avez accès à :</p>\n    <ul>\n        <li>Gestion du catalogue de livres</li>\n        <li>Gestion des utilisateurs et des emprunts</li>\n        <li>Paramètres du système</li>\n        <li>Rapports et statistiques</li>\n    </ul>\n</div>\n<p><strong>Pour commencer :</strong></p>\n<ol>\n    <li>Définissez votre mot de passe en cliquant sur le bouton ci-dessous</li>\n    <li>Accédez au tableau de bord administrateur</li>\n</ol>\n<p style=\"text-align: center; margin: 30px 0;\">\n    <a href=\"{{reset_url}}\" style=\"background-color: #10b981; color: white; padding: 12px 30px; text-decoration: none; border-radius: 8px; font-size: 16px; display: inline-block; margin: 10px;\">🔐 Définir mon mot de passe</a>\n    <a href=\"{{dashboard_url}}\" style=\"background-color: #3b82f6; color: white; padding: 12px 30px; text-decoration: none; border-radius: 8px; font-size: 16px; display: inline-block; margin: 10px;\">📊 Tableau de bord</a>\n</p>\n<div style=\"background-color: #fef3c7; padding: 15px; border-radius: 5px; margin: 20px 0;\">\n    <p><strong>⏰ Important</strong></p>\n    <p>Le lien de création de mot de passe est valide pendant 24 heures.</p>\n</div>\n<p>Bienvenue dans l''équipe !</p>','E-mail envoyé lorsqu''un utilisateur est invité en tant qu''administrateur.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (16,'loan_pickup_ready','fr_FR','📦 Livre prêt à être récupéré !','<h2>Livre prêt à être récupéré !</h2>\n<p>Bonjour {{user_name}},</p>\n<p>Nous avons le plaisir de vous informer que votre livre est prêt à être récupéré !</p>\n<div style=\"background-color: #f0f9ff; padding: 20px; border-radius: 10px; border-left: 4px solid #3b82f6; margin: 20px 0;\">\n    <h3 style=\"color: #1e40af; margin: 0 0 10px 0;\">{{book_title}}</h3>\n    <p style=\"margin: 5px 0;\"><strong>Période d''emprunt :</strong> {{start_date}} - {{end_date}}</p>\n    <p style=\"margin: 5px 0;\"><strong>Date limite de retrait :</strong> {{pickup_deadline}}</p>\n</div>\n<div style=\"background-color: #ecfdf5; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #10b981;\">\n    <p><strong>📦 Retrait</strong></p>\n    <p>{{pickup_instructions}}</p>\n</div>\n<p>Bonne lecture !</p>','Envoyé lorsqu''un emprunt a été approuvé et que le livre est prêt à être récupéré.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (17,'loan_pickup_expired','fr_FR','⏰ Délai de retrait expiré','<h2>Délai de retrait expiré</h2>\n<p>Bonjour {{user_name}},</p>\n<p>Malheureusement, vous n''avez pas récupéré le livre dans le délai imparti.</p>\n<div style=\"background-color: #fef2f2; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #ef4444;\">\n    <p><strong>Livre :</strong> {{book_title}}</p>\n    <p><strong>Date limite de retrait :</strong> {{pickup_deadline}}</p>\n</div>\n<p>L''emprunt a été automatiquement annulé et le livre est maintenant disponible pour d''autres utilisateurs.</p>\n<p>Si vous souhaitez toujours emprunter ce livre, veuillez soumettre une nouvelle demande.</p>\n<p>Cordialement,<br>L''équipe de la bibliothèque</p>','Envoyé lorsque le délai de retrait expire et que l''emprunt est automatiquement annulé.',1,NULL,NULL);
INSERT IGNORE INTO `email_templates` VALUES (18,'loan_pickup_cancelled','fr_FR','❌ Retrait annulé','<h2>Retrait annulé</h2>\n<p>Bonjour {{user_name}},</p>\n<p>Nous vous informons que le retrait du livre suivant a été annulé :</p>\n<div style=\"background-color: #fef2f2; padding: 15px; border-radius: 5px; margin: 20px 0; border-left: 4px solid #ef4444;\">\n    <p><strong>Livre :</strong> {{book_title}}</p>\n    <p><strong>Motif :</strong> {{reason}}</p>\n</div>\n<p>Le livre est maintenant disponible pour d''autres utilisateurs. Si vous souhaitez toujours l''emprunter, veuillez soumettre une nouvelle demande.</p>\n<p>Cordialement,<br>L''équipe de la bibliothèque</p>','Envoyé lorsqu''un retrait est annulé par l''administrateur.',1,NULL,NULL);
