INSERT INTO `home_content` (section_key, title, subtitle, content, button_text, button_link, is_active, display_order, created_at, updated_at) VALUES
('hero', 'Votre bibliothèque numérique', 'Découvrez, réservez et gérez votre collection de livres', NULL, 'Découvrir le catalogue', '/catalogue', 1, -2, NOW(), NOW()),
('features_title', 'Pourquoi choisir Pinakes', 'Une expérience bibliothécaire moderne et intuitive, toujours à portée de main', NULL, NULL, NULL, 1, 0, NOW(), NOW()),
('feature_1', 'Gestion simplifiée', 'Cataloguez vos livres, gérez les emprunts et les retours avec une interface intuitive et rapide', 'fas fa-tasks', NULL, NULL, 1, 1, NOW(), NOW()),
('feature_2', 'Catalogisation complète', 'Importez des données via ISBN, organisez par catégories, créez des étiquettes et suivez chaque exemplaire physique', 'fas fa-book', NULL, NULL, 1, 2, NOW(), NOW()),
('feature_3', 'Système de gestion des emprunts', 'Gérez les prêts, les échéances, les renouvellements et les notifications automatiques par e-mail pour les utilisateurs et le personnel', 'fas fa-exchange-alt', NULL, NULL, 1, 3, NOW(), NOW()),
('feature_4', 'Open Source & Gratuit', 'Logiciel 100 % libre, sans frais de licence. Personnalisez et contribuez au projet Pinakes', 'fas fa-code-branch', NULL, NULL, 1, 4, NOW(), NOW()),
('text_content', 'Πίνακες (Pinakes) - « Les Tables »', NULL, '<p>Le nom <strong>Pinakes</strong> vient du grec ancien <em>πίνακες</em> (pinakes), signifiant « tables » ou « tableaux ». Il rend hommage à <strong>Callimaque de Cyrène</strong> (305-240 av. J.-C.), qui réalisa vers 245 av. J.-C. le premier catalogue bibliothécaire systématique de l''histoire pour la Bibliothèque d''Alexandrie : les <em>Πίνακες τῶν ἐν πάσῃ παιδείᾳ διαλαμψάντων καὶ ὧν συνέγραψαν</em> (« Tables de ceux qui se sont illustrés dans tous les domaines du savoir et de leurs œuvres »).</p><p>Cette œuvre monumentale, composée de 120 rouleaux, organisait systématiquement plus de 120 000 rouleaux de papyrus de la Bibliothèque. Bien que les <em>Pinakes</em> originaux soient perdus, leur méthode de catalogisation a profondément influencé la bibliothéconomie moderne.</p><p>Ce projet perpétue cette tradition vieille de <strong>2 268 ans</strong>, apportant les mêmes principes d''organisation et d''accessibilité du savoir à l''ère numérique.</p>', NULL, NULL, 1, 4, NOW(), NOW()),
('latest_books_title', 'Dernières acquisitions', 'Découvrez les derniers ajouts au catalogue', NULL, NULL, NULL, 1, 5, NOW(), NOW()),
('genre_carousel', 'Découvrez les genres principaux', 'Explorez nos racines thématiques et laissez-vous inspirer par les titres disponibles.', NULL, NULL, NULL, 1, 6, NOW(), NOW()),
('events', 'Événements à venir', 'Participez à nos prochaines rencontres', NULL, NULL, NULL, 1, 7, NOW(), NOW()),
('cta', 'Prêt à commencer ?', 'Inscrivez-vous maintenant et commencez à explorer notre catalogue', NULL, 'S''inscrire maintenant', '/inscription', 1, 8, NOW(), NOW())
